    current_database() as database_name,
    version() as postgresql_version,
    NOW() as verification_timestamp;

SELECT
    '📋 SCHEMA STATISTICS' as report_section,
    COUNT(*) as total_tables
FROM information_schema.tables
WHERE table_schema = 'public' AND table_type = 'BASE TABLE';

SELECT
    '📋 INDEX STATISTICS' as report_section,
    COUNT(*) as total_indexes
FROM pg_indexes
WHERE schemaname = 'public';

SELECT
    '📋 ENUM STATISTICS' as report_section,
    COUNT(*) as total_enums
FROM pg_type
WHERE typtype = 'e';

-- Check materialized views (performance feature)
SELECT
    '📋 MATERIALIZED VIEWS' as report_section,
    COUNT(*) as total_materialized_views
FROM pg_matviews
WHERE schemaname = 'public';

-- Show current Alembic version
SELECT
    '🎯 ALEMBIC STATUS' as report_section,
    version_num as current_version,
    '20251010_000000' as target_version,
    CASE WHEN version_num = '20251010_000000' THEN '✅ SUCCESS' ELSE '❌ MISMATCH' END as status
FROM alembic_version;

